class Solution(object):
    def modifyString(self, s):
        s_list = list(s)
        for i in range(len(s)):
            if s_list[i] == '?':
                for char in 'abc':
                    if (i == 0 or s_list[i-1] != char) and (i == len(s)-1 or s_list[i+1] != char):
                        s_list[i] = char
                        break
        return ''.join(s_list)
